const now = new Date();
const pad = n => String(n).padStart(2, '0');
const data = `${now.getFullYear()}-${pad(now.getMonth()+1)}-${pad(now.getDate())}`;
const hora = `${pad(now.getHours())}:${pad(now.getMinutes())}`;
const horaSlug = hora.replace(':', '');

const msg = $('Telegram Trigger').item.json.message;
const tipo = $('Classifica Tipo').item.json.tipo || 'texto';

let titulo = '';
let conteudo = '';
let url = '';

if (tipo === 'url') {
  url = msg.text;
  // Extrai title tag do HTML se disponível
  const html = $input.item.json || '';
  const titleMatch = typeof html === 'string' ? html.match(/<title[^>]*>([^<]+)<\/title>/i) : null;
  titulo = titleMatch ? titleMatch[1].trim().substring(0, 80) : 'Link capturado';
  titulo = titulo.replace(/[^a-zA-Z0-9À-ÿ\s\-]/g, '').trim();
} else if (tipo === 'texto') {
  const texto = msg.text || msg.caption || '';
  titulo = texto.substring(0, 60).replace(/[^a-zA-Z0-9À-ÿ\s\-]/g, '').trim();
  conteudo = texto;
} else if (tipo === 'foto') {
  titulo = msg.caption ? msg.caption.substring(0, 60) : 'Foto capturada';
  conteudo = msg.caption || '';
} else if (tipo === 'audio') {
  titulo = 'Audio capturado';
  conteudo = '[Áudio — transcrever na próxima sessão]';
}

const slugTitulo = titulo.toLowerCase()
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9\s-]/g, '')
  .trim().replace(/\s+/g, '-').substring(0, 50);

const nomeArquivo = `${data}-${horaSlug}-${slugTitulo}.md`;

const frontmatter = [
  '---',
  `tipo: ${tipo}`,
  `fonte: telegram`,
  `data: ${data}`,
  `hora: "${hora}"`,
  url ? `url: "${url}"` : null,
  `titulo: "${titulo}"`,
  `tags: [captura, ${tipo}]`,
  `processado: false`,
  '---'
].filter(Boolean).join('\n');

const corpo = tipo === 'url'
  ? `\n# ${titulo}\n\nCapturado via Telegram em ${data} ${hora}\n\n**URL:** ${url}\n`
  : `\n# ${titulo}\n\nCapturado via Telegram em ${data} ${hora}\n\n${conteudo}\n`;

const markdownCompleto = frontmatter + corpo;
const caminhoArquivo = `cerebro/CEREBRO-ORACULO/00-INBOX/${nomeArquivo}`;

return [{
  json: {
    nomeArquivo,
    caminhoArquivo,
    markdownCompleto,
    titulo,
    tipo,
    data,
    hora,
    base64Content: Buffer.from(markdownCompleto).toString('base64')
  }
}];
